import{_ as c,r as i,o as u,c as d,a as e,b as t,t as s,d as o,w as h,e as l}from"./app-d223f2a5.js";const w={},p={id:"frontmatter-title-관련",tabindex:"-1"},m=e("a",{class:"header-anchor",href:"#frontmatter-title-관련","aria-hidden":"true"},"#",-1),f={class:"table-of-contents"},g=e("hr",null,null,-1),y=e("h2",{id:"project-11-part-4",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#project-11-part-4","aria-hidden":"true"},"#"),t(" Project 11, part 4")],-1),_=e("p",null,"After a few days of following along with me making a project, it’s time for you to step out of your comfort zone and start writing your own code. Once again, these are challenges I’m setting you based on everything you’ve learned so far, which means they are absolutely within your grasp if you set your mind to it.",-1),b=e("p",null,"Amy Morin, a social worker turned author, once said “the more you practice tolerating discomfort, the more confidence you'll gain in your ability to accept new challenges.” This is the underlying goal in all these challenges: giving you a little nudge to try something yourself, to figure out what works, and – bluntly – to screw up a few times before you figure out the right solution.",-1),k=e("p",null,"There is value in getting things right, but there’s just as much value in getting things wrong. Embrace that – learn to tolerate the discomfort that goes hand-in-hand with writing fresh code yourself – and you’ll be a great developer.",-1),v=e("p",null,"Today you should work through the wrap up chapter for project 11, complete its review, then work through all three of its challenges.",-1),j=e("h3",{id:"bookworm-wrap-up",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#bookworm-wrap-up","aria-hidden":"true"},"#"),t(" Bookworm: Wrap up")],-1),x={class:"hint-container details"},I=l('<summary>Bookworm: Wrap up</summary><p>Congratulations on finishing another SwiftUI project! With technologies like SwiftData at your side, you’re now capable of building some serious apps that interact with the user and – most importantly – <em>remember</em> what they entered. Although we only scratched the surface or SwiftData, it’s capable of a <em>lot</em> more and I expect Apple to keep expanding the link between SwiftData and SwiftUI in future updates. In the meantime, the very next project focuses deeply on SwiftData – there’s lots to explore!</p><p>As for the other things you learned, you’ve now even more of SwiftUI’s property wrappers, and I hope you’re getting a sense for which one to choose and when. <code>@Binding</code> is particularly useful when building custom UI components, because its ability to share data between views is just so useful.</p><p>There’s one last thing I’d like to leave you with, and it’s something you might not even have noticed. When we built a star rating component, we created something that became a user-interactive control just like <code>Button</code> and <code>Slider</code>. However, we <em>didn’t</em> stop to consider how it works with accessibility and that’s a problem: <code>Button</code>, <code>Slider</code>, and others work great of the box, but as soon as we start creating our <em>own</em> components we need to step in and do that work ourselves.</p><p>Building apps that are accessible for everyone is something everyone needs to take seriously, which is why I’ve dedicated a whole technique project to it in the future – we’re going to be looking back at the previous projects we’ve made and seeing how we can improve them.</p><p>Anyway, first things first – you have a new review and some challenges. Good luck!</p><h4 id="review-what-you-learned" tabindex="-1"><a class="header-anchor" href="#review-what-you-learned" aria-hidden="true">#</a> Review what you learned</h4><p>Anyone can sit through a tutorial, but it takes actual work to remember what was taught. It’s my job to make sure you take as much from these tutorials as possible, so I’ve prepared a short review to help you check your learning.</p>',8),B={href:"https://www.hackingwithswift.com/review/ios-swiftui/bookworm",target:"_blank",rel:"noopener noreferrer"},S=l('<h4 id="challenge" tabindex="-1"><a class="header-anchor" href="#challenge" aria-hidden="true">#</a> Challenge</h4><p>One of the best ways to learn is to write your own code as often as possible, so here are three ways you should try extending this app to make sure you fully understand what’s going on.</p><ol><li>Right now it’s possible to select no title, author, or genre for books, which causes a problem for the detail view. Please fix this, either by forcing defaults, validating the form, or showing a default picture for unknown genres – you can choose.</li><li>Modify <code>ContentView</code> so that books rated as 1 star are highlighted somehow, such as having their name shown in red.</li><li>Add a new “date” attribute to the Book class, assigning <code>Date.now</code> to it so it gets the current date and time, then format that nicely somewhere in <code>DetailView</code>.</li></ol>',3),A={class:"hint-container info"},D=e("p",{class:"hint-container-title"},"Bookworm: Wrap up - Additional",-1),C={href:"https://www.hackingwithswift.com/review/ios-swiftui/bookworm",target:"_blank",rel:"noopener noreferrer"},T=e("p",null,"Share something online about what you learned, or how you might use it in the future – do you like SwiftData? Are you keen to create more custom user interface components? Tell folks – stay accountable!",-1);function V(a,W){const n=i("router-link"),r=i("ExternalLinkIcon");return u(),d("div",null,[e("h1",p,[m,t(" "+s(a.$frontmatter.title)+" 관련",1)]),e("blockquote",null,[e("p",null,s(a.$frontmatter.description),1)]),e("nav",f,[e("ul",null,[e("li",null,[o(n,{to:"#project-11-part-4"},{default:h(()=>[t("Project 11, part 4")]),_:1}),e("ul",null,[e("li",null,[o(n,{to:"#bookworm-wrap-up"},{default:h(()=>[t("Bookworm: Wrap up")]),_:1})])])])])]),g,y,_,b,k,v,j,e("details",x,[I,e("p",null,[e("a",B,[t("Click here to review what you learned in this project."),o(r)])]),S]),e("div",A,[D,e("p",null,[e("a",C,[t("Review for Project 11: Bookworm"),o(r)])])]),T])}const N=c(w,[["render",V],["__file","56.html.vue"]]);export{N as default};
